import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  User, Shield, Mail, Trash2, Edit, Save, 
  X, Loader2, AlertCircle, Crown, Users, Key, RefreshCw
} from 'lucide-react';

const Perfil = () => {
  const [perfil, setPerfil] = useState(null);
  const [usuarios, setUsuarios] = useState([]);
  const [loading, setLoading] = useState(true);
  const [editandoNome, setEditandoNome] = useState(false);
  const [novoNome, setNovoNome] = useState('');
  const [novaSenha, setNovaSenha] = useState('');
  const [erroLocal, setErroLocal] = useState(null);

  useEffect(() => { carregarDados(); }, []);

  const carregarDados = async () => {
    try {
      setLoading(true);
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;

      const { data: meuPerfil } = await supabase.from('profiles').select('*').eq('id', user.id).single();

      if (meuPerfil) {
        setPerfil(meuPerfil);
        setNovoNome(meuPerfil.nome || '');
        if (meuPerfil.tipo_usuario === 'proprietario') {
          const { data: lista } = await supabase.from('profiles').select('*').order('nome', { ascending: true });
          setUsuarios(lista || []);
        }
      }
    } catch (err) { setErroLocal("Erro ao carregar dados."); } 
    finally { setLoading(false); }
  };

  const atualizarNome = async () => {
    const { error } = await supabase.from('profiles').update({ nome: novoNome }).eq('id', perfil.id);
    if (!error) { setPerfil({ ...perfil, nome: novoNome }); setEditandoNome(false); }
  };

  const alterarSenha = async () => {
    if (novaSenha.length < 6) return alert("A senha deve ter no mínimo 6 caracteres.");
    const { error } = await supabase.auth.updateUser({ password: novaSenha });
    if (error) alert("Erro: " + error.message);
    else { alert("Senha alterada com sucesso!"); setNovaSenha(''); }
  };

  const mudarCargo = async (usuarioId, novoCargo) => {
    const { error } = await supabase.from('profiles').update({ tipo_usuario: novoCargo }).eq('id', usuarioId);
    if (!error) {
      setUsuarios(usuarios.map(u => u.id === usuarioId ? { ...u, tipo_usuario: novoCargo } : u));
      // Se você mudar o cargo de alguém para proprietário, lembre-se que os metadados do AUTH dele só mudarão no próximo login dele.
    }
  };

  if (loading) return <div style={containerCenter}><Loader2 className="animate-spin" size={48} color="#4361ee" /></div>;

  return (
    <div style={{ padding: '40px 20px', maxWidth: '900px', margin: '0 auto' }}>
      <h1 style={titleStyle}>Meu Perfil</h1>

      {/* CARD DE INFORMAÇÕES PESSOAIS */}
      <section style={mainCardStyle}>
        <div style={{ flex: 1 }}>
          <label style={labelStyle}>Nome</label>
          <div style={{ display: 'flex', gap: '10px', marginBottom: '20px' }}>
            <input value={novoNome} onChange={(e) => setNovoNome(e.target.value)} style={inputStyle} />
            <button onClick={atualizarNome} style={btnSave}><Save size={18} /></button>
          </div>

          <label style={labelStyle}>Segurança (Nova Senha)</label>
          <div style={{ display: 'flex', gap: '10px' }}>
            <input type="password" placeholder="Digite a nova senha" value={novaSenha} onChange={(e) => setNovaSenha(e.target.value)} style={inputStyle} />
            <button onClick={alterarSenha} style={btnPass}><Key size={18} /> Atualizar Senha</button>
          </div>
        </div>
      </section>

      {/* PAINEL ADMINISTRATIVO (SÓ PARA PROPRIETÁRIO) */}
      {perfil?.tipo_usuario === 'proprietario' && (
        <section style={{ marginTop: '50px' }}>
          <h3 style={sectionTitle}><Users size={20} /> Gestão de Acessos</h3>
          <div style={{ display: 'grid', gap: '10px' }}>
            {usuarios.map(u => (
              <div key={u.id} style={userRow}>
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 700 }}>{u.nome}</div>
                  <div style={{ fontSize: '0.8rem', color: '#64748b' }}>{u.email}</div>
                </div>
                
                {u.id !== perfil.id && (
                  <select 
                    value={u.tipo_usuario} 
                    onChange={(e) => mudarCargo(u.id, e.target.value)}
                    style={selectStyle}
                  >
                    <option value="comum">Comum</option>
                    <option value="proprietario">Proprietário</option>
                  </select>
                )}
                
                <span style={badgeStyle(u.tipo_usuario)}>{u.tipo_usuario}</span>
              </div>
            ))}
          </div>
        </section>
      )}
    </div>
  );
};

// --- ESTILOS RÁPIDOS ---
const mainCardStyle = { background: '#fff', padding: '30px', borderRadius: '24px', boxShadow: '0 10px 15px rgba(0,0,0,0.05)', border: '1px solid #f1f5f9' };
const inputStyle = { padding: '10px', borderRadius: '12px', border: '1px solid #e2e8f0', flex: 1 };
const btnSave = { background: '#4361ee', color: '#fff', border: 'none', borderRadius: '12px', padding: '10px 20px', cursor: 'pointer' };
const btnPass = { background: '#0f172a', color: '#fff', border: 'none', borderRadius: '12px', padding: '10px 20px', cursor: 'pointer', display: 'flex', gap: '8px', alignItems: 'center' };
const userRow = { display: 'flex', alignItems: 'center', padding: '15px 20px', background: '#fff', borderRadius: '16px', border: '1px solid #f1f5f9', gap: '15px' };
const selectStyle = { padding: '5px 10px', borderRadius: '8px', border: '1px solid #cbd5e1', fontSize: '0.85rem' };
const labelStyle = { fontSize: '0.7rem', fontWeight: 800, color: '#94a3b8', textTransform: 'uppercase', marginBottom: '8px', display: 'block' };
const titleStyle = { fontSize: '2rem', fontWeight: 900, marginBottom: '20px' };
const sectionTitle = { display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '20px', fontSize: '1.2rem', fontWeight: 800 };
const containerCenter = { display: 'flex', justifyContent: 'center', alignItems: 'center', height: '50vh' };
const badgeStyle = (tipo) => ({
  padding: '4px 10px', borderRadius: '8px', fontSize: '0.7rem', fontWeight: 700,
  backgroundColor: tipo === 'proprietario' ? '#4361ee20' : '#f1f5f9',
  color: tipo === 'proprietario' ? '#4361ee' : '#64748b'
});

export default Perfil;
